const query = $input.item.json.query || $input.item.json.params || {};
const mode = query['hub.mode'];
const token = query['hub.verify_token'];
const challenge = query['hub.challenge'];
const VERIFY_TOKEN = 'YOUR_VERIFY_TOKEN_HERE';
if (mode === 'subscribe' && token === VERIFY_TOKEN) {
  return [{ json: { challenge: parseInt(challenge) } }];
}
return [{ json: { challenge: 'Verification failed' } }];

const body = $input.item.json.body || $input.item.json;
let senderPsid = '';
let messageText = '';
let messageType = 'text';
let audioUrl = '';
let timestamp = Date.now();
try {
  const entry = body.entry ? body.entry[0] : body;
  const messaging = entry.messaging ? entry.messaging[0] : entry;
  senderPsid = messaging.sender ? messaging.sender.id : (body.sender_id || '');
  timestamp = messaging.timestamp || Date.now();
  if (messaging.message) {
    if (messaging.message.text) {
      messageText = messaging.message.text;
      messageType = 'text';
    } else if (messaging.message.attachments) {
      const att = messaging.message.attachments[0];
      if (att.type === 'audio') {
        audioUrl = att.payload.url;
        messageType = 'audio';
      } else {
        messageType = 'unsupported';
        messageText = '[attachment: ' + att.type + ']';
      }
    }
  } else if (messaging.postback) {
    messageText = messaging.postback.payload || messaging.postback.title || '';
    messageType = 'postback';
  }
} catch (e) { messageType = 'error'; }
return [{ json: { senderPsid, messageText, messageType, audioUrl, timestamp, dedupeKey: senderPsid + '_' + timestamp } }];

const key = $input.item.json.dedupeKey;
const staticData = $getWorkflowStaticData('global');
if (!staticData.processed) staticData.processed = {};
const now = Date.now();
Object.keys(staticData.processed).forEach(k => {
  if (now - staticData.processed[k] > 300000) delete staticData.processed[k];
});
if (staticData.processed[key]) return [];
staticData.processed[key] = now;
return [$input.item];

const transcription = $input.item.json.text || $input.item.json.transcription || '';
const prev = $('Dedup Check').item.json;
if (!transcription || transcription.trim().length < 2) {
  return [{ json: { ...prev, messageText: '__VOICE_FAILED__', messageType: 'voice_failed' } }];
}
return [{ json: { ...prev, messageText: transcription.trim(), messageType: 'voice_transcribed' } }];

const senderPsid = $input.item.json.senderPsid;
const messageText = $input.item.json.messageText;
const messageType = $input.item.json.messageType;

let allProducts = [];
try { allProducts = $('Load Products Sheet').all().map(i => i.json); } catch(e) {}

let allFaq = [];
try { allFaq = $('Load FAQ Sheet').all().map(i => i.json); } catch(e) {}

let memory = {};
try {
  const memRows = $('Load Memory Sheet').all().map(i => i.json);
  const myMem = memRows.find(r => r.senderPsid === senderPsid);
  if (myMem) memory = myMem;
} catch(e) {}

const msgLower = messageText.toLowerCase();
const keywords = msgLower.split(/\s+/).filter(w => w.length > 2);

let scoredProducts = allProducts.map(p => {
  let score = 0;
  const searchable = ((p.Product_Name||'') + ' ' + (p.Category||'') + ' ' + (p.Colors_Available||'') + ' ' + (p.Sizes_Available||'') + ' ' + (p.Description||'')).toLowerCase();
  keywords.forEach(kw => { if (searchable.includes(kw)) score++; });
  if (memory.lastCategory && searchable.includes(memory.lastCategory.toLowerCase())) score += 2;
  if (memory.lastProductName && searchable.includes(memory.lastProductName.toLowerCase())) score += 3;
  return { ...p, _score: score };
});

scoredProducts.sort((a, b) => b._score - a._score);
let contextProducts = scoredProducts.slice(0, 5).filter(p => p._score > 0);

if (contextProducts.length === 0 && memory.lastCategory) {
  contextProducts = allProducts.filter(p => p.Category && p.Category.toLowerCase() === memory.lastCategory.toLowerCase()).slice(0, 5);
}
if (contextProducts.length === 0) {
  contextProducts = allProducts.filter(p => p.In_Stock === 'YES').slice(0, 5);
}

const productContext = contextProducts.map((p, i) => (i+1) + '. ' + p.Product_Name + ' | Tk' + p.Price + ' | Size: ' + p.Sizes_Available + ' | Color: ' + p.Colors_Available + ' | Stock: ' + p.In_Stock + ' | ID: ' + p.Product_ID).join('\n');

let relevantFaq = allFaq.map(f => {
  let score = 0;
  const faqKw = (f.Keywords || '').toLowerCase().split(',').map(k => k.trim());
  keywords.forEach(kw => { if (faqKw.some(fk => fk.includes(kw))) score++; });
  return { ...f, _score: score };
}).sort((a, b) => b._score - a._score).slice(0, 3).filter(f => f._score > 0);

const faqContext = relevantFaq.map(f => 'Q: ' + f.Question + '\nA: ' + f.Answer).join('\n\n');

const memoryContext = [
  memory.lastProductName ? 'Last product: ' + memory.lastProductName : '',
  memory.lastCategory ? 'Last category: ' + memory.lastCategory : '',
  memory.lastSize ? 'Last size: ' + memory.lastSize : '',
  memory.lastColor ? 'Last color: ' + memory.lastColor : '',
  memory.lastIntent ? 'Last intent: ' + memory.lastIntent : '',
  memory.lastBotReply ? 'Last bot reply: ' + (memory.lastBotReply||'').substring(0, 120) : '',
  memory.lastUserMessage ? 'Last user msg: ' + memory.lastUserMessage : '',
  memory.lastShownProducts ? 'Last shown products: ' + memory.lastShownProducts : ''
].filter(Boolean).join('\n');

return [{ json: { senderPsid, messageText, messageType, productContext, faqContext, memoryContext, memory } }];

