const raw = $input.item.json.text || $input.item.json.content || '';
const ctx = $('Prepare AI Context').item.json;
const senderPsid = ctx.senderPsid;
const messageText = ctx.messageText;
const messageType = ctx.messageType;

let parsed;
try {
  let jsonStr = raw.trim();
  if (jsonStr.includes('```')) jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(jsonStr);
} catch (e) {
  parsed = { replyText: raw.length > 0 && raw.length < 300 ? raw : 'কিভাবে সাহায্য করতে পারি?', intent: 'unknown', confidence: 'low', aiUsed: true, needsHumanSupport: false, telegramAlertText: '', memoryUpdate: {}, selectedProductIds: [], lastShownProducts: [] };
}

if (messageType === 'voice_failed') {
  parsed.replyText = 'Voice clear বুঝতে পারিনি. Please text করে বলবেন অথবা আবার voice দিন.';
  parsed.intent = 'voice_failed';
}
if (!parsed.replyText) parsed.replyText = 'কিভাবে সাহায্য করতে পারি?';
if (parsed.replyText.length > 500) parsed.replyText = parsed.replyText.substring(0, 497) + '...';

return [{ json: { senderPsid, messageText, replyText: parsed.replyText, intent: parsed.intent || 'unknown', confidence: parsed.confidence || 'medium', aiUsed: true, needsHumanSupport: parsed.needsHumanSupport || false, telegramAlertText: parsed.telegramAlertText || '', memoryUpdate: parsed.memoryUpdate || {}, selectedProductIds: parsed.selectedProductIds || [], lastShownProducts: parsed.lastShownProducts || [] } }];

const data = $input.item.json;
const senderPsid = data.senderPsid;
const memUpdate = data.memoryUpdate || {};
const existingMem = $('Prepare AI Context').item.json.memory || {};

const updatedMemory = {
  senderPsid: senderPsid,
  lastProductId: memUpdate.lastProductId || existingMem.lastProductId || '',
  lastProductName: memUpdate.lastProductName || existingMem.lastProductName || '',
  lastCategory: memUpdate.lastCategory || existingMem.lastCategory || '',
  lastSize: memUpdate.lastSize || existingMem.lastSize || '',
  lastColor: memUpdate.lastColor || existingMem.lastColor || '',
  lastBudget: memUpdate.lastBudget || existingMem.lastBudget || '',
  lastOccasion: memUpdate.lastOccasion || existingMem.lastOccasion || '',
  lastIntent: data.intent || existingMem.lastIntent || '',
  lastUserMessage: data.messageText || '',
  lastBotReply: data.replyText || '',
  lastShownProducts: (memUpdate.lastShownProducts || existingMem.lastShownProducts || '').toString(),
  updatedAt: new Date().toISOString()
};

return [{ json: { ...data, updatedMemory } }];
